# Category: broken_access_control

from flask import Flask, send_file, request
import os
import PyPDF2

app = Flask(__name__)

INVOICES_DIR = 'invoices'

@app.route('/api/invoices/<int:invoice_id>/download')
def download_invoice(invoice_id):
    if not os.path.exists(INVOICES_DIR):
        os.makedirs(INVOICES_DIR)

    invoice_file = f'{INVOICES_DIR}/invoice_{invoice_id}.pdf'

    if os.path.exists(invoice_file):
        with open(invoice_file, 'rb') as file:
            pdf = PyPDF2.PdfFileReader(file)
            response = send_file(
                file,
                as_attachment=True,
                attachment_filename=f'invoice_{invoice_id}.pdf',
                mimetype='application/pdf'
            )
            return response
    else:
        # Handle the case when the invoice does not exist
        pass

if __name__ == '__main__':
    app.run(debug=True)